SELECT clean_content AS evaluationText
FROM clean_interaction_result
WHERE clean_content IS NOT NULL
AND clean_content != '' AND task_id = (
SELECT MAX(task_id) FROM clean_interaction_result
)


    AND interaction_time >= #{startTime}



    AND interaction_time <= #{endTime}

SELECT id, name, robot_id AS robotId, status, scheduled_time AS scheduledTime, priority FROM tm_task WHERE 1=1
AND create_time >= #{startTime}
AND create_time <= #{endTime}
AND status IN (0, 1)
ORDER BY priority DESC, scheduled_time ASC
LIMIT #{limit} OFFSET #{offset}
